```bash
python3 - <<'PY'
import re, subprocess, sys
p="llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp"
s=open(p).read()

# Find isVectorToScalar function
m = re.search(r'bool\s+VPInstruction::isVectorToScalar\(\)\s+const\s*\{', s)
if not m:
    print("ERROR: isVectorToScalar not found", file=sys.stderr)
    sys.exit(1)
start = m.end()
# find end brace
i = start; brace=1
while i < len(s) and brace > 0:
    if s[i] == '{': brace += 1
    elif s[i] == '}': brace -= 1
    i += 1
body = s[start:i-1]

# Enhance: if this instruction defines a vector type, but its operands correspond to scalar constants or uniform values, treat as vector-to-scalar.
enh = """
  // Treat recipes that materialize a vector from a scalar source (e.g., exit PHI with
  // scalar zeroinitializer) as vector-to-scalar, so we can generate only the first lane.
  if (hasResult()) {
    if (getResult()->getType()->isVectorTy()) {
      // If all operands map to constants, consider this vector coming from a scalar.
      bool AllConst = true;
      for (const VPValue *Op : operands()) {
        if (const Value *V = getUnderlyingValueForOp(Op)) {
          if (!isa<Constant>(V)) {
            AllConst = False;
            break;
          }
        }
      }
      if (AllConst)
        return true;
    }
  }
"""
# Insert at start of function body
